      80
    );

    /* text on dark */
    --color-text-on-dark: @text;

    & when not (@lookup =latte) {
      --color-element: @crust;
    }

    & when (@lookup =latte) {
      --black: @text;
      --black-a90: @text;
      --black-a75: @text;
      --black-a45: @text;
      --black-a30: @text;
      --black-a60: @subtext0;
      --black-a15: @text;
      --black-a04: @text;
      --black-a100: @text;

      --color-scrim: fadeout(@crust, 60%);
      --color-icon-on-dark: @text;

      --white: @mantle;
      --white-a06: @surface0;
      --white-a12: @surface0;
      --white-a18: @surface0;
      --white-a25: @surface0;
      --white-a30: @mantle;
      --white-a40: @mantle;
      --white-a45: @mantle;
      --white-a55: @mantle;
      --white-a60: @subtext0;
      --white-a70: @mantle;
      --white-a75: @mantle;
      --white-a85: @mantle;
      --white-a90: @mantle;
      --white-a100: @mantle;

      --warm-gray-10: @base;
      --warm-gray-20: @base;
      --warm-gray-30: @base;
      --warm-gray-40: @base;
      --warm-gray-50: @base;
      --warm-gray-60: @base;
      --warm-gray-70: @base;
      --warm-gray-80: @base;
      --warm-gray-90: @base;
      --warm-gray-100: @base;
      --warm-gray-60-a10: fadeout(@base, 90);
      --warm-gray-60-a15: fadeout(@base, 85);
      --warm-gray-60-a20: fadeout(@base, 80);
      --warm-gray-60-a25: fadeout(@base, 75);
      --warm-gray-60-a30: fadeout(@base, 70);
      --warm-gray-60-a35: fadeout(@base, 65);
    }

    .share-promoted-detour-button-legacy {
      background-color: @accent-color !important;
    }
  }
}

