/* ==UserStyle==
@name Learn X in Y Minutes Catppuccin
@namespace github.com/catppuccin/userstyles/styles/learn-x-in-y-minutes
@homepageURL https://github.com/catppuccin/userstyles/tree/main/styles/learn-x-in-y-minutes
@version 0.0.1
@updateURL https://github.com/catppuccin/userstyles/raw/main/styles/learn-x-in-y-minutes/catppuccin.user.css
@supportURL https://github.com/catppuccin/userstyles/issues?q=is%3Aopen+is%3Aissue+label%3Alearn-x-in-y-minutes
@description Soothing pastel theme for Learn X in Y Minutes
@author Catppuccin
@license MIT

@preprocessor less
@var select lightFlavor "Light Flavor" ["latte:Latte*", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha"]
@var select darkFlavor "Dark Flavor" ["latte:Latte", "frappe:Frappé", "macchiato:Macchiato", "mocha:Mocha*"]
@var select accentColor "Accent" ["rosewater:Rosewater", "flamingo:Flamingo", "pink:Pink", "mauve:Mauve*", "red:Red", "maroon:Maroon", "peach:Peach", "yellow:Yellow", "green:Green", "teal:Teal", "blue:Blue", "sapphire:Sapphire", "sky:Sky", "lavender:Lavender", "subtext0:Gray"]
==/UserStyle== */

@import url("https://python.catppuccin.com/pygments/catppuccin-variables.important.css");
  html.light {
    --ctp-rosewater: #dc8a78;
    --ctp-flamingo: #dd7878;
    --ctp-pink: #ea76cb;
    --ctp-mauve: #8839ef;
    --ctp-red: #d20f39;
    --ctp-maroon: #e64553;
    --ctp-peach: #fe640b;
    --ctp-yellow: #df8e1d;
    --ctp-green: #40a02b;
    --ctp-teal: #179299;
    --ctp-sky: #04a5e5;
    --ctp-sapphire: #209fb5;
    --ctp-blue: #1e66f5;
    --ctp-lavender: #7287fd;
    --ctp-text: #4c4f69;
    --ctp-subtext1: #5c5f77;
    --ctp-subtext0: #6c6f85;
    --ctp-overlay2: #7c7f93;
    --ctp-overlay1: #8c8fa1;
    --ctp-overlay0: #9ca0b0;
    --ctp-surface2: #acb0be;
    --ctp-surface1: #bcc0cc;
    --ctp-surface0: #ccd0da;
    --ctp-base: #eff1f5;
    --ctp-mantle: #e6e9ef;
    --ctp-crust: #dce0e8;
    color-scheme: light;
  }
  html.light ::selection {
    background-color: rgba(64, 160, 43, 0.3);
  }
  html.light input::placeholder,
  html.light textarea::placeholder {
    color: #6c6f85 !important;
  }
  html.light .highlight {
    background-color: #e6e9ef;
  }
  html.light .highlight pre {
    background-color: #e6e9ef !important;
  }
  html.light:not(.dark, .light) p {
    color: #6c6f85 !important;
  }
  html.light:not(.dark, .light) span {
    color: #4c4f69;
  }
  html.light .share {
    background-color: #e6e9ef;
    border-color: #dce0e8;
  }
  html.light .share:hover {
    background-color: #ccd0da;
  }
  html.light .theme-choice button {
    color: #4c4f69;
    background-color: #e6e9ef;
    border-color: #dce0e8;
  }
  html.light .theme-choice button:hover {
    background-color: #ccd0da;
  }
  html.light #lang-select {
    color: #4c4f69;
    background-color: #e6e9ef;
    border-color: #dce0e8;
  }
  html.light td.lang span a {
    color: #4c4f69;
    background-color: #e6e9ef;
    border-color: #dce0e8;
  }
  html.light td.lang span a:hover {
    background-color: #ccd0da;
  }
  html.light,
  html.light body {
    background-color: #eff1f5;
    color: #4c4f69;
    border-color: #eff1f5;
    box-shadow: none;
  }
  html.light td,
  html.light th {
    color: #4c4f69;
    border-bottom-color: #ccd0da;
  }
  html.light footer p {
    color: #5c5f77;
  }
  html.light a {
    color: #40a02b !important;
  }
  html.light a code {
    color: #40a02b !important;
  }
  html.light a:visited {
    color: #388c26 !important;
  }
  html.light a.active {
    color: #eff1f5 !important;
    background-color: #40a02b !important;
    border-color: #28641b !important;
  }
  html.light a.active:visited {
    background-color: #388c26 !important;
    color: #eff1f5 !important;
    border-color: #307820 !important;
  }
  html.light hr {
    border-color: #bcc0cc;
  }
  html.light code {
    background-color: #e6e9ef;
    color: #4c4f69;
  }
  html.dark {
    --ctp-rosewater: #f5e0dc;
    --ctp-flamingo: #f2cdcd;
    --ctp-pink: #f5c2e7;
    --ctp-mauve: #cba6f7;
    --ctp-red: #f38ba8;
    --ctp-maroon: #eba0ac;
    --ctp-peach: #fab387;
    --ctp-yellow: #f9e2af;
    --ctp-green: #a6e3a1;
    --ctp-teal: #94e2d5;
    --ctp-sky: #89dceb;
    --ctp-sapphire: #74c7ec;
    --ctp-blue: #89b4fa;
    --ctp-lavender: #b4befe;
    --ctp-text: #cdd6f4;
    --ctp-subtext1: #bac2de;
    --ctp-subtext0: #a6adc8;
    --ctp-overlay2: #9399b2;
    --ctp-overlay1: #7f849c;
    --ctp-overlay0: #6c7086;
    --ctp-surface2: #585b70;
    --ctp-surface1: #45475a;
    --ctp-surface0: #313244;
    --ctp-base: #1e1e2e;
    --ctp-mantle: #181825;
    --ctp-crust: #11111b;
    color-scheme: dark;
  }
  html.dark ::selection {
    background-color: rgba(166, 227, 161, 0.3);
  }
  html.dark input::placeholder,
  html.dark textarea::placeholder {
    color: #a6adc8 !important;
  }
  html.dark .highlight {
    background-color: #181825;
  }
  html.dark .highlight pre {
    background-color: #181825 !important;
  }
  html.dark:not(.dark, .light) p {
    color: #a6adc8 !important;
  }
  html.dark:not(.dark, .light) span {
    color: #cdd6f4;
  }
  html.dark .share {
    background-color: #181825;
    border-color: #11111b;
  }
  html.dark .share:hover {
    background-color: #313244;
  }
  html.dark .theme-choice button {
    color: #cdd6f4;
    background-color: #181825;
    border-color: #11111b;
  }
  html.dark .theme-choice button:hover {
    background-color: #313244;
  }
  html.dark #lang-select {
    color: #cdd6f4;
    background-color: #181825;
    border-color: #11111b;
  }
  html.dark td.lang span a {
    color: #cdd6f4;
    background-color: #181825;
    border-color: #11111b;
  }
  html.dark td.lang span a:hover {
    background-color: #313244;
  }
  html.dark,
  html.dark body {
    background-color: #1e1e2e;
    color: #cdd6f4;
    border-color: #1e1e2e;
    box-shadow: none;
  }
  html.dark td,
  html.dark th {
    color: #cdd6f4;
    border-bottom-color: #313244;
  }
  html.dark footer p {
    color: #bac2de;
  }
  html.dark a {
    color: #a6e3a1 !important;
  }
  html.dark a code {
    color: #a6e3a1 !important;
  }
  html.dark a:visited {
    color: #93dd8d !important;
  }
  html.dark a.active {
    color: #1e1e2e !important;
    background-color: #a6e3a1 !important;
    border-color: #6ed166 !important;
  }
  html.dark a.active:visited {
    background-color: #93dd8d !important;
    color: #1e1e2e !important;
    border-color: #81d77a !important;
  }
  html.dark hr {
    border-color: #45475a;
  }
  html.dark code {
    background-color: #181825;
    color: #cdd6f4;
  }
  @media (prefers-color-scheme: light) {
    html:not(.dark, .light) {
